{"cmd":"SUPABASE_URL=$(op read op://vibe_coding/sgk6fhcjdluqvnbsekjzdkftpa/SUPABASE_URL) SUPABASE_SERVICE_ROLE_KEY=[REDACTED] read op://vibe_coding/sgk6fhcjdluqvnbsekjzdkftpa/SUPABASE_SERVICE_ROLE_KEY) node --input-type=module <<'EOF'
import { createClient } from '@supabase/supabase-js';
const supabase = createClient(process.env.SUPABASE_URL, process.env.SUPABASE_SERVICE_ROLE_KEY, { auth: { persistSession: false } });
function norm(s){return String(s||'').normalize('NFD').replace(/[\u0300-\u036f]/g,'').trim().toLowerCase().replace(/[._-]+/g,' ').replace(/[^a-z0-9\s/&]+/g,'').replace(/\s+/g,' ')}
function splitNames(s){return norm(s).split(/\s*(?:\/|&| and |,)\s*/).map(x=>x.trim()).filter(Boolean)}
function lev(a,b){const m=a.length,n=b.length;const dp=Array.from({length:m+1},(_,i)=>[i]);for(let j=1;j<=n;j++)dp[0][j]=j;for(let i=1;i<=m;i++){for(let j=1;j<=n;j++){dp[i][j]=Math.min(dp[i-1][j]+1,dp[i][j-1]+1,dp[i-1][j-1]+(a[i-1]===b[j-1]?0:1));}}return dp[m][n];}
function baseScore(a,b){const na=norm(a), nb=norm(b); if(!na||!nb) return 0; if(na===nb)return 1; const sim=1-lev(na,nb)/Math.max(na.length,nb.length); return sim;}
async function allRows(q){let rows=[]; for(let from=0;;from+=1000){const {data,error}=await q.range(from,from+999); if(error) throw error; rows.push(...(data||[])); if(!data||data.length<1000) break;} return rows;}
const styleRows = await allRows(supabase.from('style_tracker_rows').select('source_sheet,designer').not('designer','is',null).neq('designer',''));
const designers = await allRows(supabase.schema('core').from('creative_designer').select('id,name,status').order('name'));
const firstCounts = new Map();
for (const d of designers) { const first=norm(d.name).split(' ')[0]; firstCounts.set(first,(firstCounts.get(first)||0)+1); }
function bestForPart(part){let best={name:null,score:0,reason:null}; const np=norm(part); for(const d of designers){const nd=norm(d.name); const first=nd.split(' ')[0]; let s=baseScore(np,nd), reason='fuzzy'; if(np===first && firstCounts.get(first)===1){s=0.96; reason='unique first name';} if(nd.split(' ').includes(np) && np.length>=4){s=Math.max(s,0.90); reason='name token';} if(s>best.score) best={name:d.name,score:s,reason};} return best;}
const counts = new Map();
for (const r of styleRows) { const raw=String(r.designer||'').trim(); if(!raw) continue; const key=norm(raw); const current=counts.get(key)||{raw, count:0, sheets:new Map()}; current.count++; current.sheets.set(r.source_sheet,(current.sheets.get(r.source_sheet)||0)+1); counts.set(key,current); }
const audit=[...counts.values()].map(item=>{const parts=splitNames(item.raw); const partMatches=parts.map(p=>({part:p,...bestForPart(p)})); const goodParts=partMatches.filter(m=>m.score>=0.82); const exactWhole=bestForPart(item.raw); const good = exactWhole.score>=0.82 || (parts.length>1 && goodParts.length===parts.length); return {...item, parts, best: exactWhole, partMatches, good};}).sort((a,b)=>Number(a.good)-Number(b.good)||b.count-a.count||a.raw.localeCompare(b.raw));
const noGood=audit.filter(x=>!x.good);
const good=audit.filter(x=>x.good);
console.log(JSON.stringify({styleRows: styleRows.length, distinctDesignerValues:audit.length, creativeDesigners:designers.length, goodMatches:good.length, noGoodMatches:noGood.length, noGood: noGood.map(x=>({value:x.raw,count:x.count,sheets:Object.fromEntries(x.sheets),best:x.best.name,score:Number(x.best.score.toFixed(3)),reason:x.best.reason})), goodExamples: good.slice(0,50).map(x=>({value:x.raw,count:x.count,best:x.best.name,score:Number(x.best.score.toFixed(3)),reason:x.best.reason,partMatches:x.partMatches}))}, null, 2));
EOF","workdir":"/worksp/popdam","yield_time_ms":10000,"max_output_tokens":30000}

